  'feature.secure.desc': { en: 'End-to-end encryption and GDPR-compliant data handling.', zh: '端到端加密，符合GDPR的数据处理。', es: 'Encriptación de extremo a extremo y cumplimiento con GDPR.', fr: 'Chiffrement de bout en bout et conformité RGPD.', de: 'Ende-zu-Ende-Verschlüsselung und DSGVO-konform.', ja: 'エンドツーエンド暗号化とGDPR準拠のデータ処理。', ko: '종단간 암호화 및 GDPR 준수 데이터 처리.', pt: 'Criptografia de ponta a ponta e conformidade com GDPR.', ar: 'تشفير من طرف إلى طرف ومعالجة بيانات متوافقة مع GDPR.', hi: 'एंड-टू-एंड एन्क्रिप्शन और GDPR अनुपालन।', ru: 'Сквозное шифрование и соответствие GDPR.', it: 'Crittografia end-to-end e conformità GDPR.' },
  'feature.analytics': { en: 'Real-time Analytics', zh: '实时分析', es: 'Análisis en tiempo real', fr: 'Analyses en temps réel', de: 'Echtzeit-Analysen', ja: 'リアルタイム分析', ko: '실시간 분석', pt: 'Análises em tempo real', ar: 'تحليلات فورية', hi: 'रीयल-टाइम एनालिटिक्स', ru: 'Аналитика в реальном времени', it: 'Analisi in tempo reale' },
  'feature.analytics.desc': { en: 'Watch responses come in live and visualize trends instantly.', zh: '实时查看回复并即时可视化趋势。', es: 'Ve las respuestas en vivo y visualiza tendencias al instante.', fr: 'Suivez les réponses en direct et visualisez les tendances.', de: 'Verfolgen Sie Antworten live und visualisieren Sie Trends.', ja: '回答をリアルタイムで確認し、トレンドを即座に可視化。', ko: '응답을 실시간으로 확인하고 트렌드를 즉시 시각화하세요.', pt: 'Veja respostas ao vivo e visualize tendências instantaneamente.', ar: 'شاهد الاستجابات مباشرة وتصور الاتجاهات فوراً.', hi: 'लाइव प्रतिक्रियाएं देखें और तुरंत ट्रेंड विज़ुअलाइज़ करें।', ru: 'Наблюдайте за ответами в реальном времени.', it: 'Guarda le risposte in tempo reale e visualizza i trend.' },
  'feature.export': { en: 'Data Export', zh: '数据导出', es: 'Exportación de datos', fr: 'Exportation de données', de: 'Datenexport', ja: 'データエクスポート', ko: '데이터 내보내기', pt: 'Exportação de dados', ar: 'تصدير البيانات', hi: 'डेटा निर्यात', ru: 'Экспорт данных', it: 'Esportazione dati' },
  'feature.export.desc': { en: 'Export to CSV, Excel, or integrate via API.', zh: '导出为CSV、Excel，或通过API集成。', es: 'Exporta a CSV, Excel o integra vía API.', fr: 'Exportez en CSV, Excel ou intégrez via API.', de: 'Exportieren Sie nach CSV, Excel oder über API.', ja: 'CSV、ExcelへのエクスポートまたはAPI連携。', ko: 'CSV, Excel로 내보내기 또는 API를 통해 통합.', pt: 'Exporte para CSV, Excel ou integre via API.', ar: 'تصدير إلى CSV أو Excel أو التكامل عبر API.', hi: 'CSV, Excel में निर्यात करें या API से एकीकृत करें।', ru: 'Экспорт в CSV, Excel или интеграция через API.', it: 'Esporta in CSV, Excel o integra via API.' },
  'feature.templates': { en: 'Research Templates', zh: '研究模板', es: 'Plantillas de investigación', fr: 'Modèles de recherche', de: 'Forschungsvorlagen', ja: '研究テンプレート', ko: '연구 템플릿', pt: 'Modelos de pesquisa', ar: 'قوالب البحث', hi: 'शोध टेम्पलेट', ru: 'Шаблоны исследований', it: 'Modelli di ricerca' },
  'feature.templates.desc': { en: 'Start fast with validated, peer-reviewed survey templates.', zh: '使用经过验证的同行评审问卷模板快速开始。', es: 'Comienza rápido con plantillas validadas y revisadas por pares.', fr: 'Démarrez vite avec des modèles validés et évalués par les pairs.', de: 'Starten Sie schnell mit validierten Vorlagen.', ja: '検証済みの査読済みテンプレートで素早くスタート。', ko: '검증된 동료 심사 설문 템플릿으로 빠르게 시작하세요.', pt: 'Comece rápido com modelos validados e revisados por pares.', ar: 'ابدأ سريعاً بقوالب موثقة ومراجعة.', hi: 'सत्यापित, सहकर्मी-समीक्षित टेम्पलेट्स के साथ तेजी से शुरू करें।', ru: 'Быстрый старт с проверенными шаблонами.', it: 'Inizia velocemente con modelli validati e peer-reviewed.' },

