  'useCase.uxResearch.desc': { en: 'Usability tests, user interviews, and product feedback.', zh: '可用性测试、用户访谈和产品反馈。', es: 'Pruebas de usabilidad, entrevistas de usuario y comentarios de producto.', fr: "Tests d'utilisabilité, entretiens utilisateur et retours produit.", de: 'Usability-Tests, Nutzerinterviews und Produktfeedback.', ja: 'ユーザビリティテスト、ユーザーインタビュー、製品フィードバック。', ko: '사용성 테스트, 사용자 인터뷰, 제품 피드백.', pt: 'Testes de usabilidade, entrevistas e feedback de produto.', ar: 'اختبارات قابلية الاستخدام، مقابلات المستخدمين، وملاحظات المنتج.', hi: 'प्रयोज्यता परीक्षण, उपयोगकर्ता साक्षात्कार, और उत्पाद प्रतिक्रिया।', ru: 'Юзабилити-тесты, интервью, обратная связь по продукту.', it: 'Test di usabilità, interviste utente e feedback sul prodotto.' },
  'useCase.marketResearch': { en: 'Market Research', zh: '市场研究', es: 'Investigación de mercado', fr: 'Étude de marché', de: 'Marktforschung', ja: '市場調査', ko: '시장 조사', pt: 'Pesquisa de mercado', ar: 'أبحاث السوق', hi: 'बाजार शोध', ru: 'Маркетинговые исследования', it: 'Ricerca di mercato' },
