  'useCase.hr': { en: 'Human Resources', zh: '人力资源', es: 'Recursos humanos', fr: 'Ressources humaines', de: 'Personalwesen', ja: '人事', ko: '인사', pt: 'Recursos humanos', ar: 'الموارد البشرية', hi: 'मानव संसाधन', ru: 'Управление персоналом', it: 'Risorse umane' },
  'useCase.hr.desc': { en: 'Employee engagement, onboarding surveys, and 360° reviews.', zh: '员工参与度、入职问卷和360°评估。', es: 'Compromiso del empleado, encuestas de incorporación y evaluaciones 360°.', fr: "Engagement des employés, enquêtes d'intégration et évaluations 360°.", de: 'Mitarbeiterengagement, Onboarding-Umfragen und 360°-Bewertungen.', ja: '従業員エンゲージメント、オンボーディング調査、360°レビュー。', ko: '직원 참여, 온보딩 설문, 360° 리뷰.', pt: 'Engajamento do funcionário, pesquisas de integração e avaliações 360°.', ar: 'مشاركة الموظفين، استطلاعات التأهيل، ومراجعات 360°.', hi: 'कर्मचारी जुड़ाव, ऑनबोर्डिंग सर्वेक्षण, और 360° समीक्षा।', ru: 'Вовлечённость сотрудников, опросы при онбординге, 360°.', it: "Engagement dei dipendenti, sondaggi di onboarding e revisioni a 360°." },
