  'step.design': { en: 'Design', zh: '设计', es: 'Diseñar', fr: 'Concevoir', de: 'Entwerfen', ja: 'デザイン', ko: '디자인', pt: 'Projetar', ar: 'تصميم', hi: 'डिज़ाइन', ru: 'Дизайн', it: 'Progetta' },
  'step.design.desc': { en: 'Build your survey with our drag-and-drop builder or let AI generate it.', zh: '使用拖放构建器创建问卷，或让AI自动生成。', es: 'Crea tu encuesta con nuestro constructor o deja que la IA la genere.', fr: 'Construisez votre sondage avec notre éditeur ou laissez l\'IA le générer.', de: 'Erstellen Sie Ihre Umfrage per Drag & Drop oder lassen Sie KI sie generieren.', ja: 'ドラッグ&ドロップビルダーで調査を作成、またはAIに生成させる。', ko: '드래그 앤 드롭 빌더로 설문조사를 만들거나 AI가 생성하게 하세요.', pt: 'Construa sua pesquisa com nosso construtor ou deixe a IA gerar.', ar: 'ابنِ استطلاعك باستخدام أداة السحب والإفلات أو دع الذكاء الاصطناعي يولده.', hi: 'हमारे ड्रैग-एंड-ड्रॉप बिल्डर से अपना सर्वेक्षण बनाएं या AI से बनवाएं।', ru: 'Создайте опрос с помощью конструктора или позвольте ИИ сгенерировать его.', it: 'Costruisci il tuo sondaggio con il nostro editor o lascia che l\'IA lo generi.' },
  'step.distribute': { en: 'Distribute', zh: '分发', es: 'Distribuir', fr: 'Distribuer', de: 'Verteilen', ja: '配信', ko: '배포', pt: 'Distribuir', ar: 'توزيع', hi: 'वितरण', ru: 'Распространение', it: 'Distribuisci' },
  'step.distribute.desc': { en: 'Share via link, QR code, email, or embed on your website.', zh: '通过链接、二维码、邮件或嵌入网站分享。', es: 'Comparte por enlace, código QR, email o incrustar en tu sitio.', fr: 'Partagez par lien, QR code, email ou intégrez sur votre site.', de: 'Teilen Sie per Link, QR-Code, E-Mail oder betten Sie ein.', ja: 'リンク、QRコード、メール、またはウェブサイトへの埋め込みで共有。', ko: '링크, QR 코드, 이메일 또는 웹사이트에 삽입하여 공유하세요.', pt: 'Compartilhe por link, QR code, email ou incorpore no seu site.', ar: 'شارك عبر رابط أو رمز QR أو بريد إلكتروني أو ضمّنه في موقعك.', hi: 'लिंक, QR कोड, ईमेल या अपनी वेबसाइट पर एम्बेड करके साझा करें।', ru: 'Поделитесь ссылкой, QR-кодом, email или встройте на сайт.', it: 'Condividi tramite link, codice QR, email o incorpora nel tuo sito.' },
