  'step.analyze.desc': { en: 'Get real-time dashboards, charts, and export data for deeper analysis.', zh: '获取实时仪表板、图表，并导出数据进行深入分析。', es: 'Obtén dashboards en tiempo real, gráficos y exporta datos para análisis.', fr: 'Obtenez des tableaux de bord en temps réel, des graphiques et exportez les données.', de: 'Erhalten Sie Echtzeit-Dashboards, Diagramme und exportieren Sie Daten.', ja: 'リアルタイムダッシュボード、チャートを取得し、データをエクスポート。', ko: '실시간 대시보드, 차트를 얻고 데이터를 내보내세요.', pt: 'Obtenha dashboards em tempo real, gráficos e exporte dados.', ar: 'احصل على لوحات معلومات فورية ورسوم بيانية وصدّر البيانات.', hi: 'रीयल-टाइम डैशबोर्ड, चार्ट प्राप्त करें और गहन विश्लेषण के लिए डेटा निर्यात करें।', ru: 'Дашборды в реальном времени, графики и экспорт данных.', it: 'Ottieni dashboard in tempo reale, grafici ed esporta dati per analisi approfondite.' },

