  'features.ai.title': { en: 'AI that makes research easier', zh: 'AI让研究更轻易', es: 'IA que facilita la investigación', fr: "L'IA qui simplifie la recherche", de: 'KI die Forschung vereinfacht', ja: '研究を簡単にするAI', ko: '연구를 쉽게 만드는 AI', pt: 'IA que facilita a pesquisa', ar: 'ذكاء اصطناعي يسهل البحث', hi: 'AI जो शोध को आसान बनाता है', ru: 'ИИ, упрощающий исследования', it: "IA che semplifica la ricerca" },
  'features.ai.subtitle': { en: 'From question generation to response analysis, AI assists every step.', zh: '从问题生成到回复分析，AI辅助每一步。', es: 'Desde la generación de preguntas hasta el análisis, la IA ayuda en cada paso.', fr: "De la génération de questions à l'analyse, l'IA aide à chaque étape.", de: 'Von der Fragenerstellung bis zur Analyse – KI hilft bei jedem Schritt.', ja: '質問生成から回答分析まで、AIがすべてのステップを支援。', ko: '질문 생성부터 응답 분석까지, AI가 모든 단계를 지원합니다.', pt: 'Da geração de perguntas à análise, a IA ajuda em cada etapa.', ar: 'من إنشاء الأسئلة إلى تحليل الردود، الذكاء الاصطناعي يساعد في كل خطوة.', hi: 'प्रश्न निर्माण से प्रतिक्रिया विश्लेषण तक, AI हर कदम में सहायता करता है।', ru: 'От генерации вопросов до анализа ответов — ИИ помогает на каждом этапе.', it: "Dalla generazione delle domande all'analisi, l'IA assiste in ogni fase." },
  'features.aiBuilder': { en: 'AI Survey Builder', zh: 'AI问卷构建器', es: 'Constructor de encuestas IA', fr: 'Constructeur IA', de: 'KI-Umfrage-Builder', ja: 'AIアンケートビルダー', ko: 'AI 설문 빌더', pt: 'Construtor IA', ar: 'منشئ الاستطلاعات بالذكاء الاصطناعي', hi: 'AI सर्वेक्षण बिल्डर', ru: 'ИИ-конструктор опросов', it: 'Costruttore IA' },
  'features.aiBuilder.desc': { en: 'Describe your topic and AI generates a complete questionnaire.', zh: '描述您的主题，AI即可生成完整问卷。', es: 'Describe tu tema y la IA genera un cuestionario completo.', fr: "Décrivez votre sujet et l'IA génère un questionnaire.", de: 'Beschreiben Sie Ihr Thema und KI erstellt einen Fragebogen.', ja: 'トピックを説明するとAIが完全なアンケートを生成。', ko: '주제를 설명하면 AI가 설문지를 생성합니다.', pt: 'Descreva o tema e a IA gera um questionário.', ar: 'صف موضوعك وسيقوم الذكاء الاصطناعي بإنشاء استبيان.', hi: 'अपना विषय बताएं और AI प्रश्नावली बनाता है।', ru: 'Опишите тему, и ИИ создаст анкету.', it: "Descrivi l'argomento e l'IA genera un questionario." },
  'features.aiAutoAnswer': { en: 'AI Auto-Answer', zh: 'AI自动回答', es: 'Respuesta automática IA', fr: 'Réponse auto IA', de: 'KI Auto-Antwort', ja: 'AI自動回答', ko: 'AI 자동 응답', pt: 'Resposta automática IA', ar: 'الإجابة التلقائية بالذكاء الاصطناعي', hi: 'AI ऑटो-उत्तर', ru: 'ИИ авто-ответ', it: 'Risposta automatica IA' },
  'features.aiAutoAnswer.desc': { en: 'AI assists participants with contextual guidance and suggestions.', zh: 'AI为参与者提供上下文引导和建议。', es: 'La IA asiste con orientación contextual.', fr: "L'IA assiste avec des conseils contextuels.", de: 'KI unterstützt mit kontextbezogener Anleitung.', ja: 'AIが文脈に応じたガイダンスを提供。', ko: 'AI가 맥락에 맞는 안내를 제공합니다.', pt: 'IA auxilia com orientações contextuais.', ar: 'الذكاء الاصطناعي يساعد بتوجيهات سياقية.', hi: 'AI प्रासंगिक मार्गदर्शन प्रदान करता है।', ru: 'ИИ помогает участникам контекстными подсказками.', it: "L'IA assiste con suggerimenti contestuali." },
  'features.voiceInput': { en: 'Voice Input', zh: '语音输入', es: 'Entrada de voz', fr: 'Entrée vocale', de: 'Spracheingabe', ja: '音声入力', ko: '음성 입력', pt: 'Entrada de voz', ar: 'إدخال صوتي', hi: 'वॉयस इनपुट', ru: 'Голосовой ввод', it: 'Input vocale' },
  'features.voiceInput.desc': { en: 'Participants can speak their answers instead of typing.', zh: '参与者可以用语音回答，无需打字。', es: 'Los participantes pueden hablar en lugar de escribir.', fr: 'Les participants peuvent parler au lieu de taper.', de: 'Teilnehmer können sprechen statt tippen.', ja: '参加者はタイピングの代わりに音声で回答可能。', ko: '참가자가 타이핑 대신 음성으로 답변할 수 있습니다.', pt: 'Participantes podem falar em vez de digitar.', ar: 'يمكن للمشاركين التحدث بدلاً من الكتابة.', hi: 'प्रतिभागी टाइप करने के बजाय बोल सकते हैं।', ru: 'Участники могут говорить вместо набора текста.', it: 'I partecipanti possono parlare invece di digitare.' },
  'features.chatbot': { en: 'AI Chatbot', zh: 'AI聊天机器人', es: 'Chatbot IA', fr: 'Chatbot IA', de: 'KI-Chatbot', ja: 'AIチャットボット', ko: 'AI 챗봇', pt: 'Chatbot IA', ar: 'روبوت الدردشة', hi: 'AI चैटबॉट', ru: 'ИИ-чатбот', it: 'Chatbot IA' },
  'features.chatbot.desc': { en: 'Conversational survey experience powered by AI.', zh: 'AI驱动的对话式问卷体验。', es: 'Experiencia conversacional impulsada por IA.', fr: 'Expérience conversationnelle propulsée par IA.', de: 'KI-gestütztes Gesprächs-Umfrageerlebnis.', ja: 'AIによる対話型アンケート体験。', ko: 'AI 기반 대화형 설문 경험.', pt: 'Experiência conversacional com IA.', ar: 'تجربة استطلاع حوارية مدعومة بالذكاء الاصطناعي.', hi: 'AI द्वारा संचालित संवादात्मक सर्वेक्षण अनुभव।', ru: 'Разговорный опрос на основе ИИ.', it: "Esperienza di sondaggio conversazionale con IA." },
  'features.platform.label': { en: 'Platform', zh: '平台', es: 'Plataforma', fr: 'Plateforme', de: 'Plattform', ja: 'プラットフォーム', ko: '플랫폼', pt: 'Plataforma', ar: 'المنصة', hi: 'प्लेटफ़ॉर्म', ru: 'Платформа', it: 'Piattaforma' },
