  'features.webMobile': { en: 'Web & Mobile', zh: '网页与移动端', es: 'Web y móvil', fr: 'Web et mobile', de: 'Web & Mobile', ja: 'ウェブ＆モバイル', ko: '웹 및 모바일', pt: 'Web e mobile', ar: 'الويب والجوال', hi: 'वेब और मोबाइल', ru: 'Веб и мобильная версия', it: 'Web e mobile' },
  'features.webMobile.desc': { en: 'Works on any device with responsive design.', zh: '响应式设计，适用于任何设备。', es: 'Funciona en cualquier dispositivo.', fr: 'Fonctionne sur tout appareil.', de: 'Funktioniert auf jedem Gerät.', ja: 'レスポンシブデザインであらゆるデバイスに対応。', ko: '반응형 디자인으로 모든 기기에서 작동.', pt: 'Funciona em qualquer dispositivo.', ar: 'يعمل على أي جهاز.', hi: 'किसी भी डिवाइस पर काम करता है।', ru: 'Работает на любом устройстве.', it: 'Funziona su qualsiasi dispositivo.' },
  'features.mobileFirst': { en: 'Mobile App', zh: '移动应用', es: 'App móvil', fr: 'Application mobile', de: 'Mobile App', ja: 'モバイルアプリ', ko: '모바일 앱', pt: 'App móvel', ar: 'تطبيق الجوال', hi: 'मोबाइल ऐप', ru: 'Мобильное приложение', it: 'App mobile' },
  'features.mobileFirst.desc': { en: 'Native-like experience for participants on mobile.', zh: '为移动端参与者提供类原生体验。', es: 'Experiencia nativa para participantes en móvil.', fr: 'Expérience native sur mobile.', de: 'Native-ähnliche Erfahrung auf Mobilgeräten.', ja: 'モバイルでネイティブに近い体験。', ko: '모바일에서 네이티브와 같은 경험.', pt: 'Experiência nativa no celular.', ar: 'تجربة شبيهة بالتطبيقات الأصلية.', hi: 'मोबाइल पर नेटिव-जैसा अनुभव।', ru: 'Нативный опыт на мобильных устройствах.', it: 'Esperienza nativa su mobile.' },
  'features.analytics': { en: 'Real-time Analytics', zh: '实时分析', es: 'Análisis en tiempo real', fr: 'Analyses en temps réel', de: 'Echtzeit-Analysen', ja: 'リアルタイム分析', ko: '실시간 분석', pt: 'Análises em tempo real', ar: 'تحليلات فورية', hi: 'रीयल-टाइम एनालिटिक्स', ru: 'Аналитика в реальном времени', it: 'Analisi in tempo reale' },
  'features.analytics.desc': { en: 'Watch responses come in and visualize trends instantly.', zh: '实时查看回复并即时可视化趋势。', es: 'Ve las respuestas en vivo y visualiza tendencias.', fr: 'Suivez les réponses en direct et visualisez les tendances.', de: 'Verfolgen Sie Antworten live und sehen Sie Trends.', ja: '回答をリアルタイムで確認し、トレンドを即座に可視化。', ko: '응답을 실시간으로 확인하고 트렌드를 시각화하세요.', pt: 'Veja respostas ao vivo e visualize tendências.', ar: 'شاهد الاستجابات مباشرة.', hi: 'लाइव प्रतिक्रियाएं देखें और ट्रेंड देखें।', ru: 'Наблюдайте за ответами в реальном времени.', it: 'Guarda le risposte in tempo reale.' },
  'features.dashboards': { en: 'Custom Dashboards', zh: '自定义仪表板', es: 'Dashboards personalizados', fr: 'Tableaux de bord personnalisés', de: 'Benutzerdefinierte Dashboards', ja: 'カスタムダッシュボード', ko: '맞춤 대시보드', pt: 'Dashboards personalizados', ar: 'لوحات معلومات مخصصة', hi: 'कस्टम डैशबोर्ड', ru: 'Пользовательские дашборды', it: 'Dashboard personalizzate' },
  'features.dashboards.desc': { en: 'Build visual reports and share insights with stakeholders.', zh: '构建可视化报告并与利益相关者分享洞察。', es: 'Crea informes visuales y comparte con las partes interesadas.', fr: 'Créez des rapports visuels et partagez.', de: 'Erstellen Sie visuelle Berichte und teilen Sie Erkenntnisse.', ja: 'ビジュアルレポートを作成し、関係者と共有。', ko: '시각적 보고서를 만들고 이해관계자와 공유하세요.', pt: 'Crie relatórios visuais e compartilhe insights.', ar: 'أنشئ تقارير مرئية وشارك الأفكار.', hi: 'दृश्य रिपोर्ट बनाएं और हितधारकों के साथ साझा करें।', ru: 'Создавайте визуальные отчёты и делитесь.', it: 'Crea report visivi e condividi con gli stakeholder.' },
