  'features.privacy': { en: 'Privacy & Security', zh: '隐私与安全', es: 'Privacidad y seguridad', fr: 'Confidentialité et sécurité', de: 'Datenschutz & Sicherheit', ja: 'プライバシーとセキュリティ', ko: '프라이버시 및 보안', pt: 'Privacidade e segurança', ar: 'الخصوصية والأمان', hi: 'गोपनीयता और सुरक्षा', ru: 'Конфиденциальность и безопасность', it: 'Privacy e sicurezza' },
  'features.privacy.desc': { en: 'GDPR-compliant with encryption and anonymous responses.', zh: '符合GDPR，支持加密和匿名响应。', es: 'Cumple con GDPR, encriptación y respuestas anónimas.', fr: 'Conforme RGPD avec chiffrement et réponses anonymes.', de: 'DSGVO-konform mit Verschlüsselung und anonymen Antworten.', ja: 'GDPR準拠、暗号化、匿名回答対応。', ko: 'GDPR 준수, 암호화 및 익명 응답.', pt: 'Conforme LGPD com criptografia e respostas anônimas.', ar: 'متوافق مع GDPR مع التشفير والردود المجهولة.', hi: 'एन्क्रिप्शन और गुमनाम प्रतिक्रियाओं के साथ GDPR अनुपालन।', ru: 'Соответствие GDPR, шифрование и анонимные ответы.', it: 'Conforme al GDPR con crittografia e risposte anonime.' },
