  'pricing.readySubtitle': { en: 'Join thousands of researchers using Easier Research.', zh: '加入数千名使用 Easier Research 的研究人员。', es: 'Únete a miles de investigadores que usan Easier.', fr: 'Rejoignez des milliers de chercheurs utilisant Easier.', de: 'Schließen Sie sich tausenden Forschern an.', ja: '何千人もの研究者がEasier Researchを利用しています。', ko: '수천 명의 연구자가 Easier Research를 사용하고 있습니다.', pt: 'Junte-se a milhares de pesquisadores.', ar: 'انضم إلى آلاف الباحثين.', hi: 'हज़ारों शोधकर्ताओं से जुड़ें।', ru: 'Присоединяйтесь к тысячам исследователей.', it: 'Unisciti a migliaia di ricercatori.' },
  'pricing.faq1.q': { en: 'Can I switch plans later?', zh: '以后可以换方案吗？', es: '¿Puedo cambiar de plan después?', fr: 'Puis-je changer de plan plus tard ?', de: 'Kann ich später den Plan wechseln?', ja: '後でプランを変更できますか？', ko: '나중에 플랜을 변경할 수 있나요?', pt: 'Posso trocar de plano depois?', ar: 'هل يمكنني تغيير الخطة لاحقاً؟', hi: 'क्या मैं बाद में योजना बदल सकता हूँ?', ru: 'Могу ли я сменить план позже?', it: 'Posso cambiare piano in seguito?' },
  'pricing.faq1.a': { en: 'Yes, you can upgrade or downgrade at any time. Changes take effect at the next billing cycle.', zh: '是的，您可以随时升级或降级。更改将在下一个计费周期生效。', es: 'Sí, puedes actualizar o bajar de plan en cualquier momento.', fr: 'Oui, vous pouvez changer à tout moment.', de: 'Ja, Sie können jederzeit wechseln.', ja: 'はい、いつでもアップグレードまたはダウングレードできます。', ko: '네, 언제든지 업그레이드 또는 다운그레이드할 수 있습니다.', pt: 'Sim, você pode alterar a qualquer momento.', ar: 'نعم، يمكنك الترقية أو التخفيض في أي وقت.', hi: 'हाँ, आप कभी भी बदल सकते हैं।', ru: 'Да, вы можете изменить план в любое время.', it: 'Sì, puoi cambiare in qualsiasi momento.' },
  'pricing.faq2.q': { en: 'Is there a free trial for Pro?', zh: '专业版有免费试用吗？', es: '¿Hay prueba gratuita para Pro?', fr: "Y a-t-il un essai gratuit pour Pro ?", de: 'Gibt es eine kostenlose Testversion für Pro?', ja: 'Proの無料トライアルはありますか？', ko: 'Pro의 무료 체험이 있나요?', pt: 'Há teste grátis do Pro?', ar: 'هل هناك تجربة مجانية لـ Pro؟', hi: 'क्या Pro के लिए मुफ्त ट्रायल है?', ru: 'Есть ли бесплатная пробная версия Pro?', it: "C'è una prova gratuita per Pro?" },
  'pricing.faq2.a': { en: 'Yes! All Pro features are available for 14 days at no cost.', zh: '是的！所有专业版功能可免费使用14天。', es: '¡Sí! Todas las funciones Pro disponibles por 14 días.', fr: 'Oui ! Toutes les fonctionnalités Pro pendant 14 jours.', de: 'Ja! Alle Pro-Funktionen 14 Tage kostenlos.', ja: 'はい！Pro機能を14日間無料でお試しいただけます。', ko: '네! Pro 기능을 14일간 무료로 사용할 수 있습니다.', pt: 'Sim! Todos os recursos Pro por 14 dias grátis.', ar: 'نعم! جميع ميزات Pro متاحة لمدة 14 يوماً مجاناً.', hi: 'हाँ! सभी Pro सुविधाएं 14 दिनों के लिए मुफ्त।', ru: 'Да! Все функции Pro доступны 14 дней бесплатно.', it: 'Sì! Tutte le funzionalità Pro per 14 giorni gratis.' },
  'pricing.faq3.q': { en: 'What happens to my data if I downgrade?', zh: '如果降级我的数据会怎样？', es: '¿Qué pasa con mis datos si bajo de plan?', fr: "Qu'arrive-t-il à mes données si je rétrograde ?", de: 'Was passiert mit meinen Daten beim Downgrade?', ja: 'ダウングレードするとデータはどうなりますか？', ko: '다운그레이드하면 데이터는 어떻게 되나요?', pt: 'O que acontece com meus dados se fizer downgrade?', ar: 'ماذا يحدث لبياناتي إذا خفضت الخطة؟', hi: 'डाउनग्रेड करने पर मेरे डेटा का क्या होगा?', ru: 'Что будет с данными при понижении плана?', it: 'Cosa succede ai miei dati se faccio downgrade?' },
  'pricing.faq3.a': { en: 'Your data is always preserved. You just lose access to premium features.', zh: '您的数据始终保留。您只是失去对高级功能的访问权限。', es: 'Tus datos siempre se conservan.', fr: 'Vos données sont toujours conservées.', de: 'Ihre Daten bleiben immer erhalten.', ja: 'データは常に保持されます。', ko: '데이터는 항상 보존됩니다.', pt: 'Seus dados são sempre preservados.', ar: 'بياناتك محفوظة دائماً.', hi: 'आपका डेटा हमेशा सुरक्षित रहता है।', ru: 'Ваши данные всегда сохраняются.', it: 'I tuoi dati sono sempre preservati.' },
  'pricing.faq4.q': { en: 'Do you offer student discounts?', zh: '提供学生折扣吗？', es: '¿Ofrecen descuentos para estudiantes?', fr: 'Offrez-vous des réductions étudiants ?', de: 'Gibt es Studentenrabatte?', ja: '学生割引はありますか？', ko: '학생 할인이 있나요?', pt: 'Vocês oferecem desconto para estudantes?', ar: 'هل تقدمون خصومات للطلاب؟', hi: 'क्या आप छात्र छूट प्रदान करते हैं?', ru: 'Есть ли скидки для студентов?', it: 'Offrite sconti per studenti?' },
  'pricing.faq4.a': { en: 'Yes! Students and academic institutions get 50% off Pro plans. Contact us with your .edu email.', zh: '是的！学生和学术机构可享受专业版50%的折扣。请用.edu邮箱联系我们。', es: '¡Sí! 50% de descuento para estudiantes. Contáctenos con su email .edu.', fr: 'Oui ! 50% de réduction pour les étudiants. Contactez-nous avec votre email .edu.', de: 'Ja! 50% Rabatt für Studenten. Kontaktieren Sie uns mit Ihrer .edu-E-Mail.', ja: 'はい！学生は50%割引。.eduメールでお問い合わせください。', ko: '네! 학생은 50% 할인. .edu 이메일로 문의하세요.', pt: 'Sim! 50% de desconto para estudantes. Contate-nos com seu email .edu.', ar: 'نعم! 50% خصم للطلاب. تواصل معنا بريد .edu.', hi: 'हाँ! छात्रों को 50% छूट। अपने .edu ईमेल से संपर्क करें।', ru: 'Да! 50% скидка для студентов. Свяжитесь с нами через .edu email.', it: 'Sì! 50% di sconto per studenti. Contattaci con la tua email .edu.' },

